import{_ as a,o as t,c as r,a2 as n}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Chapter 8: Streaming and Realtime","description":"Mastering HTTP streaming protocols, server-sent events, and incremental rendering to build responsive real-time agent interfaces.","frontmatter":{"title":"Chapter 8: Streaming and Realtime","description":"Mastering HTTP streaming protocols, server-sent events, and incremental rendering to build responsive real-time agent interfaces."},"headers":[],"relativePath":"learn/linear/08-streaming-and-realtime/index.md","filePath":"learn/linear/08-streaming-and-realtime/index.md"}'),i={name:"learn/linear/08-streaming-and-realtime/index.md"};function l(s,e,o,m,h,d){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="streaming-and-realtime" tabindex="-1">Streaming and Realtime <a class="header-anchor" href="#streaming-and-realtime" aria-label="Permalink to &quot;Streaming and Realtime&quot;">​</a></h1><p>This chapter tackles one of the most user-visible aspects of a coding agent: streaming responses in real time. When an LLM generates a response token by token, the agent must receive those tokens over HTTP, parse the streaming protocol, and render them incrementally to the user. The difference between a snappy, responsive agent and one that feels sluggish comes down to how well this streaming pipeline is engineered.</p><p>We begin with the HTTP-level protocols that make streaming possible: chunked transfer encoding and server-sent events (SSE). You will learn how these protocols work at the wire level, how to parse them correctly in Rust, and how to handle the many edge cases that arise with partial JSON payloads, network interruptions, and backpressure. These are not abstract concerns — every production LLM API uses one of these protocols.</p><p>The chapter then moves to the application-level challenges of streaming: how to render partial content without flickering, how to handle user interrupts mid-stream, how to reconnect after network failures, and how to manage buffering for optimal throughput and latency. You will build the streaming infrastructure that later chapters depend on for terminal rendering and conversation state management.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Understand HTTP streaming protocols including chunked encoding and server-sent events at the wire level</li><li>Parse SSE streams in Rust with correct handling of event types, retry fields, and multi-line data</li><li>Handle partial JSON payloads that arrive mid-stream without valid parse boundaries</li><li>Implement backpressure and flow control between the network layer and the rendering layer</li><li>Build reconnection logic with exponential backoff and stream resumption</li><li>Design buffering strategies that balance latency and throughput for real-time display</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/08-streaming-and-realtime/01-why-streaming-matters.html">Why Streaming Matters</a></li><li><a href="/linear/08-streaming-and-realtime/02-http-streaming-protocols.html">HTTP Streaming Protocols</a></li><li><a href="/linear/08-streaming-and-realtime/03-server-sent-events.html">Server Sent Events</a></li><li><a href="/linear/08-streaming-and-realtime/04-chunked-encoding.html">Chunked Encoding</a></li><li><a href="/linear/08-streaming-and-realtime/05-parsing-sse-in-rust.html">Parsing SSE in Rust</a></li><li><a href="/linear/08-streaming-and-realtime/06-partial-json-handling.html">Partial JSON Handling</a></li><li><a href="/linear/08-streaming-and-realtime/07-incremental-rendering.html">Incremental Rendering</a></li><li><a href="/linear/08-streaming-and-realtime/08-backpressure-and-flow-control.html">Backpressure and Flow Control</a></li><li><a href="/linear/08-streaming-and-realtime/09-interrupt-and-cancel.html">Interrupt and Cancel</a></li><li><a href="/linear/08-streaming-and-realtime/10-reconnection-strategies.html">Reconnection Strategies</a></li><li><a href="/linear/08-streaming-and-realtime/11-buffering-patterns.html">Buffering Patterns</a></li><li><a href="/linear/08-streaming-and-realtime/12-event-driven-architecture.html">Event Driven Architecture</a></li><li><a href="/linear/08-streaming-and-realtime/13-performance-considerations.html">Performance Considerations</a></li><li><a href="/linear/08-streaming-and-realtime/14-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 3 (LLM API streaming protocol basics and familiarity with API response formats)</li></ul>',10)])])}const p=a(i,[["render",l]]);export{g as __pageData,p as default};
